import {
  computeStyles,
  eventListeners,
  flip,
  offset,
  preventOverflow,
  type VirtualElement,
} from '@popperjs/core';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { usePopper } from 'react-popper';

import { useOverlayStacking } from '../../../../../../core/hooks/useOverlayStacking.js';
import { createDOMRect } from '../../../../../../core/utils/create-dom-rect.js';
import { observeOverlaySize } from '../../../../../../overlays/utils/popper-modifiers.js';
import type { Point } from '../../../../types/point.js';
import type { TooltipAlignment } from '../types/tooltip-shared.js';

/**
 * Positions a given chartTooltipRef correctly in the viewport and exposes the ideal tooltip marker placement and a position handler
 * @internal
 * */
export function useChartTooltip(
  /** The reference to the chart tooltip element. */
  chartTooltipElement: HTMLDivElement | null,
  /** Optional. Default alignment for tooltip. */
  defaultTooltipPlacement: TooltipAlignment = 'left',
): {
  /** Alignment reference for consistently aligning tooltip within viewport boundaries. */
  placement: TooltipAlignment;
  /** Update handler which takes care of repositioning the `chartTooltipElement` element based on the `MousePosition` payload. */
  updateTooltipPosition: (mousePosition: Point) => void;
} {
  // This element is a dot with a position relative to the mouse and is used for popperjs to determine the tooltips position
  const [virtualElement, setVirtualElement] = useState<VirtualElement>();

  const tooltipHeight = chartTooltipElement?.getBoundingClientRect().height;

  // The offset modifier will change, depending on the amount of selectedDates at a given mouse position, modifying the tooltip's height
  const popperModifiers = useMemo(() => {
    const modifiers: (
      | Partial<typeof flip>
      | Partial<typeof preventOverflow>
      | Partial<typeof offset>
      | Partial<typeof computeStyles>
      | Partial<typeof eventListeners>
      | typeof observeOverlaySize
    )[] = [
      {
        name: 'flip',
        options: {
          fallbackPlacements: [defaultTooltipPlacement],
        },
      },
      {
        name: 'preventOverflow',
        options: {
          mainAxis: true, // true is the default value so maybe it can be removed
        },
      },
      {
        name: 'computeStyles',
        options: {
          gpuAcceleration: false,
        },
      },
      { name: 'eventListeners', enabled: false },
      observeOverlaySize,
    ];
    if (tooltipHeight) {
      // Custom value for offset modifier align the marker next to the mouse
      modifiers.push({
        name: 'offset',
        options: {
          offset: () => [
            // 24 Is the SizeLarge token, but since this is needed as a numeric, it is hardcoded here for now.
            Math.round(tooltipHeight / 2 - 24),
            // 16 Is the SizeLarge token, but since this is needed as a numeric, it is hardcoded here for now.
            16,
          ], // [Aligns the tooltipmarker to the mouse, y-axis margin]
        },
      });
    }

    return modifiers;
  }, [tooltipHeight, defaultTooltipPlacement]);

  const { state, styles } = usePopper(virtualElement, chartTooltipElement, {
    strategy: 'fixed',
    placement: defaultTooltipPlacement === 'left' ? 'right' : 'left',
    modifiers: popperModifiers,
  });

  const overlayStacking = useOverlayStacking(0, 'overlay');

  useEffect(() => {
    const { top, left, right } = styles.popper;

    const display = virtualElement !== undefined ? 'block' : 'none';

    chartTooltipElement?.setAttribute(
      'style',
      `display: ${display}; position: fixed; top: ${top}; left: ${left}; right: ${right}; z-index: ${overlayStacking.style.zIndex}`,
    );
  }, [
    virtualElement,
    styles.popper,
    chartTooltipElement,
    overlayStacking.style.zIndex,
  ]);

  const updateTooltipPosition = useCallback((mousePosition: Point): void => {
    if (mousePosition) {
      setVirtualElement({
        getBoundingClientRect: createDOMRect({
          x: mousePosition.x,
          y: mousePosition.y,
        }),
      });
    } else {
      setVirtualElement(undefined);
    }
  }, []);

  return {
    placement: (state?.placement ??
      defaultTooltipPlacement) as TooltipAlignment,
    updateTooltipPosition,
  };
}
